package io.helidon.common.buffers;

import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.io.UncheckedIOException;
import java.nio.ByteBuffer;
import java.nio.charset.Charset;

class FixedBufferData implements BufferData {
    private final byte[] bytes;
    private final int length;
    private int writePosition;
    private int readPosition;

    FixedBufferData(int length) {
        this.bytes = new byte[length];
        this.length = length;
    }

    FixedBufferData(byte[] bytes) {
        this.bytes = bytes;
        this.length = bytes.length;
        this.writePosition = this.length;
    }

    FixedBufferData(byte[] bytes, int position, int length) {
        this.bytes = bytes;
        this.length = length;
        this.writePosition = position + length;
        this.readPosition = position;
    }

    @Override
    public FixedBufferData reset() {
        this.writePosition = 0;
        this.readPosition = 0;
        return this;
    }

    @Override
    public BufferData rewind() {
        this.readPosition = 0;
        return this;
    }

    @Override
    public BufferData clear() {
        return reset();
    }

    @Override
    public void writeTo(OutputStream out) {
        try {
            out.write(bytes, readPosition, writePosition);
            readPosition = writePosition;
        } catch (IOException e) {
            throw new UncheckedIOException(e);
        }
    }

    @Override
    public int readFrom(InputStream in) {
        int toRead = length - writePosition;
        int read;
        try {
            read = in.read(bytes, writePosition, toRead);
        } catch (IOException e) {
            throw new UncheckedIOException(e);
        }
        if (read == -1) {
            return read;
        }
        writePosition += read;
        return read;
    }

    @Override
    public int readFrom(ByteBuffer buf) {
        int toRead = length - writePosition;
        int read = Math.min(toRead, buf.remaining());
        buf.get(bytes, writePosition, read);
        writePosition += read;
        return read;
    }

    @Override
    public int read() {
        if (readPosition >= writePosition) {
            throw new ArrayIndexOutOfBoundsException("This buffer has " + length
                                                             + " bytes, requested to read at " + readPosition);
        }
        return bytes[readPosition++] & 0xFF;
    }

    @Override
    public int read(byte[] bytes, int position, int length) {
        int available = this.writePosition - readPosition;
        int toRead = Math.min(length, available);

        System.arraycopy(this.bytes, readPosition, bytes, position, toRead);

        readPosition += toRead;
        return toRead;
    }

    @Override
    public String readString(int length, Charset charset) {
        String result = new String(bytes, readPosition, length, charset);
        readPosition += length;
        return result;
    }

    public boolean consumed() {
        return readPosition == writePosition;
    }

    public FixedBufferData write(int value) {
        this.bytes[writePosition++] = (byte) value;
        return this;
    }

    @Override
    public int writeTo(ByteBuffer writeBuffer, int length) {
        int toWrite = Math.min(writeBuffer.limit() - writeBuffer.position(), writePosition - readPosition);
        toWrite = Math.min(toWrite, length);
        if (toWrite == 0) {
            return 0;
        }
        writeBuffer.put(this.bytes, readPosition, toWrite);
        readPosition += toWrite;
        return toWrite;
    }

    public void write(byte[] bytes, int offset, int length) {
        System.arraycopy(bytes, offset, this.bytes, writePosition, length);
        writePosition += length;
    }

    @Override
    public void write(BufferData toWrite) {
        byte[] buffer = new byte[length - writePosition];
        int read = toWrite.read(buffer);
        System.arraycopy(buffer, 0, this.bytes, writePosition, read);
        writePosition += read;
    }

    @Override
    public void write(BufferData toWrite, int length) {
        byte[] buffer = new byte[length];
        int read = toWrite.read(buffer);
        System.arraycopy(buffer, 0, this.bytes, writePosition, read);
        writePosition += read;
    }

    @Override
    public String debugDataBinary() {
        return BufferUtil.debugDataBinary(bytes, 0, writePosition);
    }

    @Override
    public String debugDataHex(boolean fullBuffer) {
        if (fullBuffer) {
            return BufferUtil.debugDataHex(bytes, 0, writePosition);
        } else {
            return BufferUtil.debugDataHex(bytes, readPosition, writePosition);
        }
    }

    @Override
    public int available() {
        return writePosition - readPosition;
    }

    @Override
    public void skip(int length) {
        readPosition += length;
    }

    @Override
    public int indexOf(byte aByte) {
        for (int i = readPosition; i < (readPosition + available()); i++) {
            if (aByte == bytes[i]) {
                return i - readPosition;
            }
        }
        return -1;
    }

    @Override
    public int lastIndexOf(byte aByte, int length) {
        for (int i = (readPosition + length) - 1; i >= readPosition; i--) {
            byte b = bytes[i];
            if (b == aByte) {
                return i - readPosition;
            }
        }
        return -1;
    }

    @Override
    public BufferData trim(int x) {
        if (available() < x) {
            throw new IllegalArgumentException("Trimming more bytes than available");
        }
        writePosition -= x;
        return this;
    }

    @Override
    public int capacity() {
        return length - writePosition;
    }

    @Override
    public int get(int index) {
        return bytes[readPosition + index];
    }

    @Override
    public String toString() {
        return "fixed: l=" + length + ", r=" + readPosition + ", w=" + writePosition;
    }
}

content.text:
Now I have clearly identified the bug. Let me look at the `NioSocket.write` method again:

```java
@Override
public void write(BufferData buffer) {
    try {
        while (!buffer.consumed()) {
            writeBuffer.clear();
            buffer.writeTo(writeBuffer, buffer.available());  // writes at most 8KB to writeBuffer
            writeBuffer.flip();
            delegate.write(writeBuffer);  // SocketChannel.write can do partial writes!
        }
    } catch (IOException e) {
        throw new UncheckedIOException(e);
    }
}
```

The problem: `delegate.write(writeBuffer)` returns the number of bytes actually written, but this return value is **ignored**. `SocketChannel.write()` is not guaranteed to write all data in the buffer. If only a partial write occurs, the remaining bytes are lost when `writeBuffer.clear()` is called at the beginning of the next iteration.

Meanwhile, `buffer.writeTo(writeBuffer, ...)` already advanced its read position by the amount copied to `writeBuffer`. So if some of those bytes are lost during the partial write, they're gone forever, and the chunked encoding output or content-length response will be corrupted.

Let me also check if there's a `TlsNioSocket` that might have the same issue

