package io.helidon.common.socket;

import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.channels.SocketChannel;

import io.helidon.common.buffers.BufferData;

import org.junit.jupiter.api.Test;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.is;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

/**
 * Tests for {@link NioSocket} write method handling of partial writes.
 */
class NioSocketWriteTest {

    /**
     * Verifies that partial writes from SocketChannel.write() are handled correctly.
     * The original bug was that the return value of SocketChannel.write() was ignored,
     * causing data corruption when the write was not complete.
     */
    @Test
    void testPartialWriteHandling() throws IOException {
        // Create a byte pattern that we can verify
        byte[] data = new byte[16384]; // 16KB - larger than the 8KB internal buffer
        for (int i = 0; i < data.length; i++) {
            data[i] = (byte) (i & 0xFF);
        }

        BufferData sourceData = BufferData.create(data);

        SocketChannel channel = mock(SocketChannel.class);
        // Simulate partial writes: each write call only writes 1024 bytes
        when(channel.write(any(ByteBuffer.class))).thenAnswer(invocation -> {
            ByteBuffer buf = invocation.getArgument(0);
            int remaining = buf.remaining();
            int toWrite = Math.min(remaining, 1024);
            buf.position(buf.position() + toWrite);
            return toWrite;
        });

        NioSocket socket = NioSocket.server(channel, "test-channel", "test-server");

        // This should write all data without corruption even with partial writes
        socket.write(sourceData);

        // Verify all data was consumed from the source buffer
        assertThat("All bytes should be consumed", sourceData.consumed(), is(true));
    }

    /**
     * Test that a large buffer (multiple rounds through the internal write buffer)
     * is written fully even with partial writes.
     */
    @Test
    void testLargeBufferWithPartialWrites() throws IOException {
        // 100KB of data - this forces multiple iterations through the 8KB internal buffer
        byte[] data = new byte[100_000];
        for (int i = 0; i < data.length; i++) {
            data[i] = (byte) ((i * 7 + 13) & 0xFF);
        }

        BufferData sourceData = BufferData.create(data);

        SocketChannel channel = mock(SocketChannel.class);
        // Simulate very small partial writes
        when(channel.write(any(ByteBuffer.class))).thenAnswer(invocation -> {
            ByteBuffer buf = invocation.getArgument(0);
            int remaining = buf.remaining();
            int toWrite = Math.min(remaining, 512);
            buf.position(buf.position() + toWrite);
            return toWrite;
        });

        NioSocket socket = NioSocket.server(channel, "test-channel", "test-server");
        socket.write(sourceData);

        assertThat("All bytes should be consumed", sourceData.consumed(), is(true));
    }

    /**
     * Test that a buffer smaller than the internal write buffer is also
     * handled correctly even with partial writes.
     */
    @Test
    void testSmallBufferWithPartialWrites() throws IOException {
        byte[] data = "Hello, World!".getBytes();
        BufferData sourceData = BufferData.create(data);

        SocketChannel channel = mock(SocketChannel.class);
        // Simulate writing 1 byte at a time
        when(channel.write(any(ByteBuffer.class))).thenAnswer(invocation -> {
            ByteBuffer buf = invocation.getArgument(0);
            int remaining = buf.remaining();
            int toWrite = Math.min(remaining, 1);
            buf.position(buf.position() + toWrite);
            return toWrite;
        });

        NioSocket socket = NioSocket.server(channel, "test-channel", "test-server");
        socket.write(sourceData);

        assertThat("All bytes should be consumed", sourceData.consumed(), is(true));
    }
}

